'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useForm, useFieldArray } from 'react-hook-form';
import { useMasterDataStore } from '@/store/useMasterDataStore';
import { useTransactionStore } from '@/store/useTransactionStore';
import { Transaction, TransactionItem } from '@/types';
import { ArrowLeft, Plus, Trash2, Save } from 'lucide-react';
import { format } from 'date-fns';

type InvoiceFormData = {
  partyId: string;
  number: string;
  date: string;
  items: TransactionItem[];
  amountPaid: number;
};

export default function NewPurchasePage() {
  const router = useRouter();
  const { parties, items: inventoryItems } = useMasterDataStore();
  const { addTransaction } = useTransactionStore();
  const [isSubmitting, setIsSubmitting] = useState(false);

  // We show vendors for purchases
  const vendors = parties.filter(p => p.type === 'vendor');

  const { register, control, handleSubmit, watch, setValue } = useForm<InvoiceFormData>({
    defaultValues: {
      partyId: '',
      number: `BILL-${Date.now().toString().slice(-6)}`,
      date: format(new Date(), 'yyyy-MM-dd'),
      items: [{ itemId: '', name: '', quantity: 1, rate: 0, discount: 0, taxRate: 18, taxAmount: 0, totalAmount: 0 }],
      amountPaid: 0
    }
  });

  const { fields, append, remove } = useFieldArray({
    control,
    name: 'items'
  });

  const watchItems = watch('items');
  const watchAmountPaid = watch('amountPaid');

  // Calculations
  const subTotal = watchItems.reduce((sum, item) => sum + ((item.quantity || 0) * (item.rate || 0)), 0);
  const discountTotal = watchItems.reduce((sum, item) => sum + (item.discount || 0), 0);
  const taxAmountTotal = watchItems.reduce((sum, item) => sum + (item.taxAmount || 0), 0);
  const grandTotal = subTotal - discountTotal + taxAmountTotal;

  // Auto-calculate line items
  useEffect(() => {
    watchItems.forEach((item, index) => {
      const qty = item.quantity || 0;
      const rate = item.rate || 0;
      const discount = item.discount || 0;
      const taxRate = item.taxRate || 0;
      
      const lineTotalBeforeTax = (qty * rate) - discount;
      const taxAmount = (lineTotalBeforeTax * taxRate) / 100;
      const totalAmount = lineTotalBeforeTax + taxAmount;

      if (item.taxAmount !== taxAmount || item.totalAmount !== totalAmount) {
        setValue(`items.${index}.taxAmount`, taxAmount);
        setValue(`items.${index}.totalAmount`, totalAmount);
      }
    });
  }, [watchItems, setValue]);

  const handleItemSelect = (index: number, itemId: string) => {
    const selectedItem = inventoryItems.find(i => i.id === itemId);
    if (selectedItem) {
      setValue(`items.${index}.name`, selectedItem.name);
      setValue(`items.${index}.rate`, selectedItem.purchasePrice);
      setValue(`items.${index}.taxRate`, selectedItem.taxRate);
    }
  };

  const onSubmit = async (data: InvoiceFormData) => {
    if (data.items.length === 0 || !data.items[0].itemId) {
      alert("Please add at least one item");
      return;
    }

    setIsSubmitting(true);
    try {
      const selectedParty = parties.find(p => p.id === data.partyId);
      
      const transactionData: Omit<Transaction, 'id'> = {
        type: 'purchase_invoice',
        number: data.number,
        date: new Date(data.date).toISOString(),
        partyId: data.partyId,
        partyName: selectedParty?.name || 'Unknown Vendor',
        items: data.items.filter(i => i.itemId),
        subTotal,
        taxAmountTotal,
        discountTotal,
        grandTotal,
        amountPaid: data.amountPaid || 0,
        status: 'draft'
      };

      await addTransaction(transactionData);
      
      // OPTIONAL TODO: trigger stock updates here using a Firebase Edge function or batch writes.
      router.push('/purchases');
    } catch (error) {
      console.error("Error saving bill:", error);
      alert("Failed to save purchase bill.");
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-6 pb-24">
      <div className="flex items-center gap-4">
        <button 
          onClick={() => router.back()}
          className="p-2 hover:bg-slate-200 rounded-full transition"
        >
          <ArrowLeft className="h-5 w-5" />
        </button>
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900">Record Purchase Bill</h1>
        </div>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700 text-red-600">Vendor *</label>
              <select 
                {...register("partyId", { required: true })}
                className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Select Vendor</option>
                {vendors.map(c => (
                  <option key={c.id} value={c.id}>{c.name} {c.gstin ? `(${c.gstin})` : ''}</option>
                ))}
              </select>
            </div>
            
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700 text-red-600">Bill No *</label>
              <input 
                {...register("number", { required: true })}
                className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700 text-red-600">Bill Date *</label>
              <input 
                type="date"
                {...register("date", { required: true })}
                className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>
        </div>

        {/* Line Items */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-4 border-b border-slate-200 bg-slate-50">
            <h2 className="font-semibold text-slate-800">Items</h2>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-100/50 text-slate-600 font-medium">
                <tr>
                  <th className="px-4 py-3 w-1/3">Item</th>
                  <th className="px-4 py-3 w-24">Qty</th>
                  <th className="px-4 py-3 w-32">Purch. Rate (₹)</th>
                  <th className="px-4 py-3 w-28">Disc (₹)</th>
                  <th className="px-4 py-3 w-28">GST (%)</th>
                  <th className="px-4 py-3 w-32">Tax (₹)</th>
                  <th className="px-4 py-3 text-right">Amount (₹)</th>
                  <th className="px-4 py-3 w-12"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {fields.map((field, index) => (
                  <tr key={field.id} className="hover:bg-slate-50/50">
                    <td className="px-4 py-3">
                      <select
                        {...register(`items.${index}.itemId`, { required: true })}
                        onChange={(e) => {
                          register(`items.${index}.itemId`).onChange(e); // Trigger RHF
                          handleItemSelect(index, e.target.value);
                        }}
                        className="w-full px-2 py-1.5 border border-slate-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                      >
                        <option value="">Select Item</option>
                        {inventoryItems.map(item => (
                          <option key={item.id} value={item.id}>{item.name}</option>
                        ))}
                      </select>
                      <input type="hidden" {...register(`items.${index}.name`)} />
                    </td>
                    <td className="px-4 py-3">
                      <input 
                        type="number" step="0.01" min="1"
                        {...register(`items.${index}.quantity`, { valueAsNumber: true })}
                        className="w-full px-2 py-1.5 border border-slate-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <input 
                        type="number" step="0.01"
                        {...register(`items.${index}.rate`, { valueAsNumber: true })}
                        className="w-full px-2 py-1.5 border border-slate-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <input 
                        type="number" step="0.01"
                        {...register(`items.${index}.discount`, { valueAsNumber: true })}
                        className="w-full px-2 py-1.5 border border-slate-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <select 
                        {...register(`items.${index}.taxRate`, { valueAsNumber: true })}
                        className="w-full px-2 py-1.5 border border-slate-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                      >
                        <option value={0}>0%</option>
                        <option value={5}>5%</option>
                        <option value={12}>12%</option>
                        <option value={18}>18%</option>
                        <option value={28}>28%</option>
                      </select>
                    </td>
                    <td className="px-4 py-3">
                      <div className="w-full px-2 py-1.5 bg-slate-100 rounded text-slate-500 text-sm">
                        {watchItems[index]?.taxAmount?.toFixed(2) || '0.00'}
                      </div>
                    </td>
                    <td className="px-4 py-3 text-right">
                      <div className="font-medium text-slate-800">
                        {watchItems[index]?.totalAmount?.toFixed(2) || '0.00'}
                      </div>
                    </td>
                    <td className="px-4 py-3 text-center">
                      <button 
                        type="button" 
                        onClick={() => remove(index)}
                        className="text-red-500 hover:text-red-700 p-1"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="p-4 border-t border-slate-200">
            <button
              type="button"
              onClick={() => append({ itemId: '', name: '', quantity: 1, rate: 0, discount: 0, taxRate: 18, taxAmount: 0, totalAmount: 0 })}
              className="flex items-center gap-2 text-sm font-medium text-blue-600 hover:text-blue-800"
            >
              <Plus className="h-4 w-4" /> Add Row
            </button>
          </div>
        </div>

        {/* Footer Totals */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 space-y-4 h-fit">
            <h3 className="font-semibold text-slate-800 border-b pb-2">Payment Setup</h3>
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Amount Paid (₹)</label>
              <input 
                type="number" step="0.01"
                {...register("amountPaid", { valueAsNumber: true })}
                className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-lg border-green-500 bg-green-50 focus:ring-green-500"
              />
            </div>
            {watchAmountPaid > 0 && (
              <p className="text-xs text-slate-500">
                To be Paid later: ₹{Math.max(0, grandTotal - (watchAmountPaid || 0)).toFixed(2)}
              </p>
            )}
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="space-y-3 text-sm">
              <div className="flex justify-between text-slate-600">
                <span>Subtotal</span>
                <span>₹{subTotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between text-slate-600">
                <span>Total Discount</span>
                <span>- ₹{discountTotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between text-slate-600">
                <span>Total Tax (GST)</span>
                <span>+ ₹{taxAmountTotal.toFixed(2)}</span>
              </div>
              <div className="pt-3 border-t border-slate-200 flex justify-between font-bold text-lg text-slate-900">
                <span>Grand Total</span>
                <span>₹{grandTotal.toFixed(2)}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Action Bar */}
        <div className="fixed bottom-0 left-0 right-0 md:pl-64 bg-white border-t border-slate-200 p-4 flex justify-end shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] z-10">
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => router.back()}
              className="px-6 py-2.5 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-md hover:bg-slate-50"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isSubmitting}
              className="px-6 py-2.5 flex items-center gap-2 text-sm font-medium text-white bg-blue-600 rounded-md hover:bg-blue-700 disabled:opacity-50"
            >
              <Save className="h-4 w-4" /> 
              {isSubmitting ? 'Saving...' : 'Save Purchase Bill'}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useTransactionStore } from '@/store/useTransactionStore';
import { useAuth } from '@/hooks/useAuth';
import { generateInvoicePDF } from '@/lib/pdf/generateInvoice';
import { ArrowLeft, Download, Printer, FileText } from 'lucide-react';
import Link from 'next/link';
import { format } from 'date-fns';

export default function InvoiceViewPage() {
  const params = useParams();
  const router = useRouter();
  const { profile } = useAuth();
  const { transactions, isLoading } = useTransactionStore();
  const [isGenerating, setIsGenerating] = useState(false);

  const invoiceId = params.id as string;
  const invoice = transactions.find(t => t.id === invoiceId);

  useEffect(() => {
    if (!isLoading && !invoice) {
      router.push('/sales');
    }
  }, [isLoading, invoice, router]);

  if (isLoading || !invoice) {
    return <div className="p-8 text-center text-slate-500">Loading invoice...</div>;
  }

  const handleDownload = async () => {
    try {
      setIsGenerating(true);
      await generateInvoicePDF(invoice, { name: profile?.name || 'My Business' });
    } catch (error) {
      console.error('Failed to generate PDF', error);
      alert('Failed to generate PDF');
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6 max-w-6xl mx-auto pb-12">
      {/* Header Actions */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <Link 
          href="/sales"
          className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors text-sm font-bold"
        >
          <ArrowLeft className="w-4 h-4" /> Back to Invoices
        </Link>
        
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button 
            onClick={() => window.print()}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-[#121c17] hover:bg-[#1a231f] text-white border border-[#1a231f] px-4 py-2.5 rounded-lg transition-colors text-sm font-bold"
          >
            <Printer className="w-4 h-4" /> Print
          </button>
          <button 
            onClick={handleDownload}
            disabled={isGenerating}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-[#00ea77] hover:bg-[#00c563] text-black px-4 py-2.5 rounded-lg transition-colors text-sm font-bold shadow-[0_0_15px_rgba(0,234,119,0.2)] disabled:opacity-50"
          >
            {isGenerating ? (
              <span className="w-4 h-4 border-2 border-black border-t-transparent rounded-full animate-spin flex-shrink-0"></span>
            ) : (
              <Download className="w-4 h-4" />
            )}
            Download PDF
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        
        {/* Left: Invoice Preview Document */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden print:shadow-none print:border-none">
          <div className="p-8 md:p-12 text-slate-900 bg-white">
            
            {/* Document Header */}
            <div className="flex justify-between items-start border-b border-slate-200 pb-8 mb-8">
              <div>
                <h2 className="text-3xl font-black tracking-tight text-slate-900 mb-2">
                  {profile?.businesses?.[0] ? 'KhataX Business' : 'My Business'}
                </h2>
                <p className="text-slate-500 text-sm font-medium">GSTIN: 29XXXXX0000X1Z5</p>
                <p className="text-slate-500 text-sm font-medium">123 Business Avenue, Tech Park</p>
              </div>
              <div className="text-right">
                <h1 className="text-4xl font-black text-[#00ea77] tracking-tighter uppercase mb-4">Invoice</h1>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-sm text-right">
                  <span className="font-bold text-slate-400 uppercase tracking-wider text-[10px]">Invoice No</span>
                  <span className="font-bold">{invoice.number}</span>
                  <span className="font-bold text-slate-400 uppercase tracking-wider text-[10px]">Date</span>
                  <span className="font-medium">{format(new Date(invoice.date), 'dd MMM yyyy')}</span>
                  {invoice.dueDate && (
                    <>
                       <span className="font-bold text-slate-400 uppercase tracking-wider text-[10px]">Due Date</span>
                       <span className="font-medium">{format(new Date(invoice.dueDate), 'dd MMM yyyy')}</span>
                    </>
                  )}
                </div>
              </div>
            </div>

            {/* Bill To */}
            <div className="mb-10">
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Bill To</h3>
              <p className="text-lg font-bold text-slate-900">{invoice.partyName}</p>
              {/* If we had party details populated, we would show them here */}
            </div>

            {/* Items Table */}
            <div className="mb-10 border border-slate-200 rounded-lg overflow-hidden">
              <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-4 py-3 font-bold text-slate-700">Item Description</th>
                    <th className="px-4 py-3 font-bold text-slate-700 text-center">Qty</th>
                    <th className="px-4 py-3 font-bold text-slate-700 text-right">Rate</th>
                    <th className="px-4 py-3 font-bold text-slate-700 text-center">Tax</th>
                    <th className="px-4 py-3 font-bold text-slate-700 text-right">Amount</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-200">
                  {invoice.items.map((item, idx) => (
                    <tr key={idx}>
                      <td className="px-4 py-3 font-medium text-slate-900">{item.name}</td>
                      <td className="px-4 py-3 font-medium text-slate-600 text-center">{item.quantity}</td>
                      <td className="px-4 py-3 font-medium text-slate-600 text-right">₹{item.rate.toFixed(2)}</td>
                      <td className="px-4 py-3 font-medium text-slate-600 text-center">{item.taxRate || 0}%</td>
                      <td className="px-4 py-3 font-bold text-slate-900 text-right">₹{item.totalAmount.toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Totals */}
            <div className="flex justify-end mb-16">
              <div className="w-full max-w-xs space-y-3">
                <div className="flex justify-between text-sm font-medium text-slate-600">
                  <span>Subtotal</span>
                  <span>₹{invoice.subTotal.toFixed(2)}</span>
                </div>
                {invoice.discountTotal > 0 && (
                   <div className="flex justify-between text-sm font-medium text-slate-600">
                    <span>Discount</span>
                    <span className="text-red-500">-₹{invoice.discountTotal.toFixed(2)}</span>
                  </div>
                )}
                <div className="flex justify-between text-sm font-medium text-slate-600 pb-3 border-b border-slate-200">
                  <span>Total Tax</span>
                  <span>₹{invoice.taxAmountTotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-xl font-black text-slate-900 pt-1">
                  <span>Total Due</span>
                  <span>₹{invoice.grandTotal.toFixed(2)}</span>
                </div>
              </div>
            </div>

            {/* Footer Notes */}
            <div className="text-center pt-8 border-t border-slate-200 text-slate-400 text-xs font-medium">
              This is a computer-generated document and requires no signature.
            </div>
            
          </div>
        </div>

        {/* Right: Actions & Details Panel (Hidden on Print) */}
        <div className="lg:col-span-1 space-y-4 print:hidden">
          
          <div className="bg-[#121c17] border border-[#1a231f] rounded-xl p-6 shadow-sm">
            <h3 className="text-sm font-bold text-white mb-4">Invoice Status</h3>
            <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-bold uppercase tracking-wider
              ${invoice.status === 'paid' ? 'bg-[#00ea77]/10 text-[#00ea77]' : 
                invoice.status === 'partially_paid' ? 'bg-yellow-500/10 text-yellow-500' : 
                'bg-red-500/10 text-red-500'}
            `}>
              <div className={`w-2 h-2 rounded-full 
                ${invoice.status === 'paid' ? 'bg-[#00ea77]' : 
                  invoice.status === 'partially_paid' ? 'bg-yellow-500' : 
                  'bg-red-500'}
              `}></div>
              {invoice.status.replace('_', ' ')}
            </div>

            <div className="mt-6 space-y-3 pt-6 border-t border-[#1a231f]">
              <div className="flex justify-between">
                <span className="text-sm text-slate-400">Total Amount</span>
                <span className="text-sm font-bold text-white">₹{invoice.grandTotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-slate-400">Amount Paid</span>
                <span className="text-sm font-bold text-[#00ea77]">₹{invoice.amountPaid.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-slate-400">Balance Due</span>
                <span className="text-sm font-bold text-red-400">₹{(invoice.grandTotal - invoice.amountPaid).toFixed(2)}</span>
              </div>
            </div>

            <button className="w-full mt-6 bg-[#0b2217] text-[#00ea77] border border-[#00ea77]/20 hover:bg-[#00ea77]/10 py-2.5 rounded-lg text-sm font-bold transition-colors">
              Record Payment
            </button>
          </div>

        </div>

      </div>
    </div>
  );
}

